import{_ as t,o as n,c as a,ag as i}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"AI-functies","description":"","frontmatter":{},"headers":[],"relativePath":"nl/advanced/ai-features.md","filePath":"nl/advanced/ai-features.md"}'),r={name:"nl/advanced/ai-features.md"};function o(s,e,l,g,c,d){return n(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="ai-functies" tabindex="-1">AI-functies <a class="header-anchor" href="#ai-functies" aria-label="Permalink to &quot;AI-functies&quot;">​</a></h1><p>MyCompanyDesk bevat AI-gestuurde functies om je sneller en slimmer te laten werken.</p><h2 id="contextuele-gids" tabindex="-1">Contextuele gids <a class="header-anchor" href="#contextuele-gids" aria-label="Permalink to &quot;Contextuele gids&quot;">​</a></h2><p>De in-app-assistent helpt je bij het navigeren door MyCompanyDesk:</p><ul><li>Klik op het <strong>hulp-icoon</strong> op elke pagina voor contextgerichte hulp</li><li>Stel vragen over functies, workflows of instellingen</li><li>Krijg stapsgewijze begeleiding bij veelvoorkomende taken</li><li>Beschikbaar in alle vier ondersteunde talen</li></ul><p>De gids begrijpt op welke pagina je je bevindt en geeft relevante suggesties.</p><h3 id="chatlimieten" tabindex="-1">Chatlimieten <a class="header-anchor" href="#chatlimieten" aria-label="Permalink to &quot;Chatlimieten&quot;">​</a></h3><p>Chatgebruik is afhankelijk van je abonnement:</p><table tabindex="0"><thead><tr><th>Abonnement</th><th>Chatberichten</th></tr></thead><tbody><tr><td>Gratis</td><td>Beperkt</td></tr><tr><td>Pro</td><td>Ruime limiet</td></tr><tr><td>Business</td><td>Hoogste limiet</td></tr></tbody></table><h2 id="ai-suggesties" tabindex="-1">AI-suggesties <a class="header-anchor" href="#ai-suggesties" aria-label="Permalink to &quot;AI-suggesties&quot;">​</a></h2><p>Slimme aanbevelingen die je helpen bij het categoriseren en beschrijven van je records:</p><h3 id="uitgavecategorisatie" tabindex="-1">Uitgavecategorisatie <a class="header-anchor" href="#uitgavecategorisatie" aria-label="Permalink to &quot;Uitgavecategorisatie&quot;">​</a></h3><p>Wanneer je een uitgave aanmaakt, analyseert AI de omschrijving en stelt de meest geschikte categorie voor. Dit bespaart tijd en zorgt voor consistente categorisatie.</p><h3 id="omschrijvingsverbeteringen" tabindex="-1">Omschrijvingsverbeteringen <a class="header-anchor" href="#omschrijvingsverbeteringen" aria-label="Permalink to &quot;Omschrijvingsverbeteringen&quot;">​</a></h3><p>AI kan duidelijkere, professionelere omschrijvingen suggereren voor:</p><ul><li>Factuurregelitems</li><li>Uitgavenomschrijvingen</li><li>Klantnotities</li></ul><h3 id="hoe-het-werkt" tabindex="-1">Hoe het werkt <a class="header-anchor" href="#hoe-het-werkt" aria-label="Permalink to &quot;Hoe het werkt&quot;">​</a></h3><ol><li>Maak een record aan of bewerk er een</li><li>Zoek naar de AI-suggestie-indicator</li><li>Bekijk de suggestie</li><li>Klik op <strong>Toepassen</strong> om deze te gebruiken, of <strong>Negeren</strong> om over te slaan</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>AI-suggesties vereisen het <strong>Pro</strong>-abonnement of hoger. Schakel ze in via <strong>Bedrijf &gt; Functies</strong>.</p></div><h2 id="bonnen-scannen" tabindex="-1">Bonnen scannen <a class="header-anchor" href="#bonnen-scannen" aria-label="Permalink to &quot;Bonnen scannen&quot;">​</a></h2><p>AI-gestuurde OCR extraheert gegevens uit bonafbeeldingen en PDF&#39;s:</p><ul><li><strong>Datum</strong> — Wanneer de aankoop is gedaan</li><li><strong>Bedrag</strong> — Totale kosten</li><li><strong>Leverancier</strong> — Aan wie je hebt betaald</li><li><strong>Omschrijving</strong> — Wat er is gekocht</li></ul><p>Zie <a href="/nl/advanced/receipt-scanning">Bonnen scannen</a> voor gedetailleerde instructies.</p><h2 id="tekstcontrole" tabindex="-1">Tekstcontrole <a class="header-anchor" href="#tekstcontrole" aria-label="Permalink to &quot;Tekstcontrole&quot;">​</a></h2><p>Grammatica- en spellingcontrole voor je documenten:</p><ul><li>Controleer factuuromschrijvingen voor het versturen</li><li>Verifieer offerte-inhoud</li><li>Corrigeer typefouten in klantgerichte tekst</li></ul><p>Ondersteunt Engels, Nederlands, Duits en Frans.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Tekstcontrole vereist het <strong>Pro</strong>-abonnement of hoger.</p></div><h2 id="accountsamenvattingen" tabindex="-1">Accountsamenvattingen <a class="header-anchor" href="#accountsamenvattingen" aria-label="Permalink to &quot;Accountsamenvattingen&quot;">​</a></h2><p>AI genereert periodieke samenvattingen van je bedrijfsactiviteit:</p><ul><li><strong>Dagelijks</strong> — Snel overzicht van de transacties van de dag</li><li><strong>Wekelijks</strong> — Weekoverzicht met trends</li><li><strong>Maandelijks</strong> — Uitgebreide maandelijkse analyse</li></ul><p>Samenvattingen worden gegenereerd in je voorkeurstaal en zijn beschikbaar vanaf het dashboard.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Schakel AI-suggesties eenmaal in en ze werken automatisch op de achtergrond</li><li>Bonnen scannen is vooral handig voor papieren bonnen — maak gewoon een foto</li><li>De contextuele gids kan de meeste &quot;hoe doe ik...&quot;-vragen over de app beantwoorden</li><li>AI-functies gebruiken privacybeschermende verwerking — je gegevens blijven veilig</li></ul>',34)])])}const p=t(r,[["render",o]]);export{u as __pageData,p as default};
